class Solution {
public:
    vector<long long> maximumEvenSplit(long long finalSum) {
        if (finalSum % 2 != 0) return {};
        vector<long long> res;
        long long i = 2;
        while (finalSum > 0 && i <= finalSum) {
            res.push_back(i);
            finalSum -= i;
            i += 2;
        }
        if (finalSum != 0) res.clear();
        return res;
    }
};
```
